module SC_MFB_140_80(CDN, CP, D0, D1, GS, Q, S, SDN, VS);
    input CDN;
    input CP;
    input D0;
    input D1;
    input GS;
    output Q;
    input S;
    input SDN;
    input VS;

    reg    Q_reg;
        
    wire D;
    
    assign   D = S ? D1 : D0;
    
    always @(posedge CP or negedge SDN or negedge CDN) begin
      if (!CDN) begin
        Q_reg <= 1'b0;
      end
      else if (!SDN) begin
        Q_reg <= 1'b1;
      end
      else begin
        Q_reg <= D;
      end
    end
    
    assign  Q  = Q_reg;


endmodule


