module SC_REGCELL_140_90S1(Q, HOLD, D0, D1, S, CP, CDN, VS, GS);
    output Q;
    input HOLD;
    input D0;
    input D1;
    input S;
    input CP;
    input CDN;
    input VS;
    input GS;

	reg    Q_reg;
    
    wire A;
	wire B;

    
    assign   A = HOLD ? Q_reg : D0;
    assign   B = S ? D1 : A;
    
    always @(posedge CP or negedge CDN) begin
      if (!CDN) begin
        Q_reg <= 1'b0;
      end
      else begin
        Q_reg <= B;
      end
    end
    
    assign   Q  =  Q_reg;

endmodule // SC_REGCELL_140_90S1


