module SC_LAS_140_80(CP, D, GS, Q, SD, VS);
    input CP;
    input D;
    input GS;
    output Q;
    input SD;
    input VS;

	reg    Q_reg;
        
    always @(CP or SD or D) begin
			if (SD) begin
				Q_reg <= 1'b1;
			end
			else if (CP) begin
				Q_reg <= D;
			end
    end
   
	assign   Q = Q_reg;

endmodule  // SC_LAS_140_80

