    output Q;
    input VS;

	reg    Q_reg;

    always @(CP or CDN or D) begin
      if (!CDN) begin
        Q_reg <= 1'b0;
      end
      else if (CP) begin
        Q_reg <= D;
      end
    end
   
	assign Q = Q_reg;

endmodule  // SC_LAC_140_80

