//-----------------------------------------------------------------------------
// Library Name: HCQ_2404150_SC_LIB_SCH
// Cell Name: SC_DFB_140_90
// View Name: netlist
//-----------------------------------------------------------------------------
module SC_DFB_140_90(CDN, CP, D, GS, Q, QN, SDN, VS);
    input CDN;
    input CP;
    input D;
    input GS;
    output Q;
    output QN;
    input SDN;
    input VS;

	reg    Q_reg;
        
    always @(posedge CP or negedge SDN or negedge CDN) begin
       	if (!CDN) begin
           	Q_reg <= 1'b0;
       	end
       	else if (!SDN) begin
           	Q_reg <= 1'b1;
       	end  
       	else begin
           	Q_reg <= D;
       	end
    end
       
	assign   Q  =  Q_reg;
	assign   QN = ~Q_reg;

endmodule  // SC_DFB_140_90

